import base64, os
dirs = ['mipmap-mdpi','mipmap-hdpi','mipmap-xhdpi','mipmap-xxhdpi','mipmap-xxxhdpi']
[os.makedirs(f'app/src/main/res/{d}', exist_ok=True) for d in dirs]
open('app/src/main/res/mipmap-mdpi/ic_launcher.png','wb').write(base64.b64decode('')); print('OK 48px')
open('app/src/main/res/mipmap-hdpi/ic_launcher.png','wb').write(base64.b64decode('')); print('OK 72px')
open('app/src/main/res/mipmap-xhdpi/ic_launcher.png','wb').write(base64.b64decode('')); print('OK 96px')
open('app/src/main/res/mipmap-xxhdpi/ic_launcher.png','wb').write(base64.b64decode('')); print('OK 144px')
open('app/src/main/res/mipmap-xxxhdpi/ic_launcher.png','wb').write(base64.b64decode('')); print('OK 192px')